var isAnomaly = probability > 0.5;

// Feature names for reference
var featureNames = [
    'RMS', 'Peak', 'Crest Factor', 'Kurtosis',
    'Skewness', 'Dom. Freq', 'Spectral Centroid', 'Band Energy'
];

// Build feature map
var features = {};
if (Array.isArray(msg.payload)) {
