    diagnosis: isAnomaly ? getDiagnosis(msg.payload) : 'Machine operating normally',
    features: features,
    modelType: 'PyTorch - ONNX',
    timestamp: new Date().toISOString()
};

// Simple diagnosis based on feature patterns
function getDiagnosis(f) {
    if (!Array.isArray(f)) return 'Unknown fault';

    // High kurtosis + crest factor = bearing
    if (f[3] > 0.7 && f[2] > 0.7) return '[CRITICAL] Bearing fault suspected';

    // High RMS + low freq = imbalance
    if (f[0] > 0.7 && f[5] < 0.3) return '[WARNING] Rotor imbalance suspected';

    // Broadband + high crest = looseness
    if (f[6] > 0.5 && f[2] > 0.6) return '[CAUTION] Mechanical looseness suspected';

    return 'Anomaly detected - check machine';
}

return msg;

