var samples = 2048;
var fs = 10000;
var shaftFreq = 25;
var gearTeeth = 20;
var gmf = shaftFreq * gearTeeth;

var signal = [];
for (var i = 0; i < samples; i++) {
    var t = i / fs;
    var v = Math.sin(2 * Math.PI * gmf * t);
    v += 0.4 * Math.sin(2 * Math.PI * (gmf - shaftFreq) * t);
    v += 0.4 * Math.sin(2 * Math.PI * (gmf + shaftFreq) * t);
    v += 0.2 * (Math.random() - 0.5);
    signal.push(v);
}
msg.payload = signal;
return msg;

// Batterie Simulation mit Entladung
// Kapazität: 300 Ah
// ZEITRAFFER: x60 (1 Zyklus = 2 Minuten simuliert statt 2 Sekunden)

flow.cycle = (flow.cycle || 0) + 1;
flow.soc = flow.soc || 100;
flow.consumedAh = flow.consumedAh || 0;

// Simulierter Stromverbrauch (variiert zwischen 10A und 25A)
var baseLoad = 15; // Grundlast 15A
var variation = (Math.sin(flow.cycle * 0.1) + 1) * 5; // 0-10A Variation
var spikes = Math.random() < 0.1 ? Math.random() * 10 : 0; // Gelegentliche Lastspitzen
var current = baseLoad + variation + spikes;

// SOC reduzieren - ZEITRAFFER x60
// Bei 300Ah: 100% = 300Ah
// 2 Sek * 60 = 2 Min pro Zyklus simuliert
var SPEEDUP = 60;
var ahPerCycle = current * (2 * SPEEDUP / 3600); // 2 Minuten simulierte Zeit
flow.consumedAh += ahPerCycle;
flow.soc = Math.max(0, 100 - (flow.consumedAh / 3)); // 300Ah = 100%

// Spannung basierend auf SOC (11.8V-14.4V Bereich für 12V LiFePO4)
var voltage = 11.8 + (flow.soc / 100) * 2.6;

// Shunt-Daten Format (wie vom echten Gerät)
msg.payload = {
    modelId: 41859,
    voltage: Math.round(voltage * 100) / 100,
    alarm: flow.soc < 20 ? "LOW_BATTERY" : "NO_ALARM",
    auxMode: "STARTER_VOLTAGE",
    current: Math.round(current * 10) / 10,
    consumedAh: Math.round(flow.consumedAh * 10) / 10,
    soc: Math.round(flow.soc * 10) / 10,
    starterVoltage: Math.round((voltage - 0.03) * 100) / 100
};

msg.timestamp = Date.now();

// Reset nach 200 Zyklen (~6.6h simuliert) oder wenn Batterie leer
if (flow.cycle > 200 || flow.soc <= 0) {
    flow.cycle = 0;
    flow.soc = 100;
    flow.consumedAh = 0;
    node.warn("Batterie Simulation zurueckgesetzt auf 100%");
}

return msg;

// Batterie Kapazität in Ah
const BATTERY_CAPACITY = 300;

// Shunt-Daten auslesen
const data = msg.payload;
const soc = data.soc;
const current = Math.abs(data.current);
const voltage = data.voltage;
const consumedAh = Math.abs(data.consumedAh);

// Für RUL-Node: Degradation = 100 - SOC
// (Wert steigt Richtung 100 = "Failure" = Batterie leer)
msg.payload = 100 - soc;
msg.timestamp = Date.now();

// Batterie-Info für spätere Verwendung
msg.battery = {
    capacity: BATTERY_CAPACITY,
    soc: soc,
    current: current,
    voltage: voltage,
    consumedAh: consumedAh,
    availableAh: Math.round((soc / 100) * BATTERY_CAPACITY * 10) / 10
};

// Einfache Restlaufzeit-Berechnung (falls kein Trend verfügbar)
if (current > 0) {
    msg.battery.simpleRuntimeHours = Math.round(msg.battery.availableAh / current * 10) / 10;
} else {
    msg.battery.simpleRuntimeHours = Infinity;
}

return msg;

const battery = msg.battery || {};
const rul = msg.rul || {};

// Restlaufzeit formatieren
let runtimeText = "";
let runtimeHours = 0;

if (rul.value === Infinity || rul.status === 'stable') {
    runtimeText = "∞ (keine Entladung / stabil)";
} else if (typeof rul.value === 'number' && isFinite(rul.value)) {
    runtimeHours = rul.value;
    const hours = Math.floor(runtimeHours);
    const mins = Math.round((runtimeHours - hours) * 60);
    runtimeText = hours + "h " + mins + "min";
} else {
    // Fallback auf einfache Berechnung
    if (battery.simpleRuntimeHours && isFinite(battery.simpleRuntimeHours)) {
        runtimeHours = battery.simpleRuntimeHours;
        const hours = Math.floor(runtimeHours);
        const mins = Math.round((runtimeHours - hours) * 60);
        runtimeText = hours + "h " + mins + "min (geschätzt)";
    } else {
        runtimeText = "Berechnung läuft...";
    }
}
msg.topic = "Batterie Status";
msg.payload = {
    "Ladezustand (SOC)": battery.soc + " %",
    "Spannung": battery.voltage + " V",
    "Strom": battery.current + " A",
    "Verfügbar": battery.availableAh + " Ah",
    "Verbraucht": battery.consumedAh + " Ah",
    "Restlaufzeit": runtimeText,
    "Konfidenz": rul.confidence ? (rul.confidence * 100).toFixed(0) + "%" : "n/a",
    "Zustand": rul.status || "berechne..."
};

// Node-Status setzen
var statusColor = "green";
if (battery.soc < 20) statusColor = "red";
else if (battery.soc < 50) statusColor = "yellow";

node.status({
    fill: statusColor,
    shape: "dot",
    text: battery.soc + "% | " + runtimeText
});

return msg;

const battery = msg.battery || {};
const rul = msg.rul || {};
const degradation = msg.degradation || {};

msg.topic = "BATTERIE WARNUNG";

msg.payload = {
    "Ladezustand": battery.soc + " %",
    "Status": rul.status || "kritisch",
    "Restlaufzeit": rul.value ? rul.value.toFixed(1) + " Stunden" : "sehr gering",
    "Degradation": degradation.percent ? degradation.percent.toFixed(1) + "%" : "hoch",
    "Trend": degradation.trend || "steigend",
