};

node.status({
    fill: "red",
    shape: "ring",
    text: "WARNUNG SOC: " + battery.soc + "%"
});

return msg;

var prediction = msg.prediction;
var maxRul = 125;  // Max RUL days
var rul = 0;

// Handle different output formats
if (Array.isArray(prediction)) {
    rul = prediction[0];
    if (Array.isArray(rul)) {
        rul = rul[0];
    }
} else if (typeof prediction === 'number') {
    rul = prediction;
} else if (prediction && prediction.data) {
    rul = prediction.data[0];
}

// Model outputs 0-1, scale to 0-125
rul = rul * maxRul;

// Determine status
var status = 'healthy';
var urgency = 'none';
if (rul < 10) {
    status = 'critical';
    urgency = 'immediate';
} else if (rul < 30) {
    status = 'warning';
    urgency = 'soon';
} else if (rul < 60) {
    status = 'degrading';
    urgency = 'scheduled';
}

msg.payload = {
    rul_days: Math.round(rul * 10) / 10,
    status: status,
    urgency: urgency,
    expected: msg.expectedRul,
    raw_prediction: prediction,
    model: 'LSTM'
};

return msg;

